function LxInstanceCtrl:_parseInscellTypeStr(typeStr)
    local typeInfo = string.split(typeStr,"=")
    local type = checknumber(typeInfo[1])
    ---@type V_Item
    local item
    ---@type number
    local weight
    if type == 1 then
        if #typeInfo >= 4 then
            item = {
                type = checknumber(typeInfo[2]),
                refId = checknumber(typeInfo[3]),
                num = checknumber(typeInfo[4]),
            }
        else
            if LOG_INFO_ENABLED then
                printInfo("配置出错：","InscellRef 表 tpye = " .. typeStr)
            end
        end
    elseif type == 2 then
        weight = checknumber(typeInfo[2])
    end
    return {
        type = type,
        item = item,
        weight = weight,
    }
end


---@return V_InscellRef[]
function LxInstanceCtrl:GetInitInscellRefsByClassType(classTpye)
    if not self._initInscellRefsList then
        self._initInscellRefsList = {}
    end
    if not self._initInscellRefMap then
        self._initInscellRefMap = {}
    end
    local initInscellRefData = self._initInscellRefsList[classTpye]
    local initInscellRefMapData = self._initInscellRefMap[classTpye]
    if not initInscellRefData or not initInscellRefMapData then
        initInscellRefData = {}
        initInscellRefMapData = {}
        for k,v in pairs(GameTable.InscellRef) do
            if v.classTpye == classTpye then
                local data = {
                    refId = k,
                    cell = v.cell,
                    classTpye = classTpye,
                    tpye = self:_parseInscellTypeStr(v.tpye),
                    passBy = v.passBy,
                    event = v.event,
                    extract = v.extract,
                    itemCheck = v.itemCheck,
                    icon = v.icon,
                    bg = v.bg,
                    fx = v.fx,
                }
                table.insert(initInscellRefData,data)
                initInscellRefMapData[k] = data
            end
        end
        table.sort(initInscellRefData, function (a,b) return a.cell < b.cell end)
        self._initInscellRefsList[classTpye] = initInscellRefData
        self._initInscellRefMap[classTpye] = initInscellRefMapData
    end
    return initInscellRefData,initInscellRefMapData
end

function LxInstanceCtrl:GetInscellTypeLen(classType)
    local initInscellRefData = self:GetInitInscellRefsByClassType(classType)
    return #initInscellRefData
end

function LxInstanceCtrl:GetInscellTypeLenByMapRefId(mapRefId)
