end

---@return LxInstanceMapObj
function LxInstanceCtrl:GetCurMapObj()
    local belongChapterId
    local instanceModule = ModuleCenter.Instance
    ---@type LxInstanceWorldObj
    local worldObj
    ---@type LxInstanceMapObj
    local mapObj
    local isSameChapter = false
    local initInsmapRefList = self:GetInitInsmapRefList()
    for i,v in ipairs(initInsmapRefList) do
        isSameChapter = belongChapterId == v.belongChapterId
        if not isSameChapter then
            belongChapterId = v.belongChapterId
            worldObj = instanceModule:GetWorldObj(belongChapterId)
        end
        if worldObj then
            mapObj = worldObj:GetMapObj(v.refId)
            if mapObj and not mapObj:IsPassMap() then
                break
            end
        end
    end
    return mapObj
end

function LxInstanceCtrl:GetCurWorldIndex()
    local instanceModule = ModuleCenter.Instance
    ---@type LxInstanceWorldObj
    local worldObj
    local initInsWorldRefs = self:GetInitInsWorldRefList()
    for i,v in ipairs(initInsWorldRefs) do
        worldObj = instanceModule:GetWorldObj(v.refId)
        if worldObj and not worldObj:CheckWorldIsPass() then
            return i
        end
    end
    return 1
end

---@return LxInstanceWorldObj
function LxInstanceCtrl:GetNotRewardWorldObj()
    local rewardNum = 0
    ---@type LxInstanceWorldObj
    local worldObj = nil
    ---@type LxInstanceWorldObj[]
    local worldObjs = ModuleCenter.Instance:GetWorldObjs()
    local initInsWorldRefs = self:GetInitInsWorldRefList()
    for i,v in ipairs(initInsWorldRefs) do
        worldObj = worldObjs[v.refId]
        if worldObj then
            if worldObj:CheckWorldIsAllReceive() then
                rewardNum = rewardNum + 1
            else
                return worldObj
            end
        end
    end
    local endRef = initInsWorldRefs[#initInsWorldRefs]
    return worldObjs[endRef.refId]
end



function LxInstanceCtrl:CheckCellIsSpecial(mapRefId,cell)
    local classType = LxDataHelper.GetInsmapClassType(mapRefId)
    if classType and classType > 0 then
        local initInscellRefs = self:GetInitInscellRefsByClassType(classType)
        local cellData = initInscellRefs[cell]
        if cellData then
            local tpye = cellData.tpye
            return tpye and tpye.type == 2
        end
    end
end

---@return V_InsWorldRewardRef
function LxInstanceCtrl:GetInitInsWorldRewardsByMapRefId(mapRefId)
    if not self._initInsWorldRewardsMap then
        self._initInsWorldRewardsMap = {}
    end
    local rewards = self._initInsWorldRewardsMap[mapRefId]
    if not rewards then
        for k,v in pairs(GameTable.InsWorldRewardRef) do
            if v.finish == mapRefId then
                rewards = {
                    refId = k,
                    reward = LxDataHelper.ParseItemList(v.reward),
                    finish = mapRefId,
                    belongChapterId = v.belongChapterId,
                    sort = v.sort,
                }
            end
        end
        self._initInsWorldRewardsMap[mapRefId] = rewards
    end
    return rewards
end



function LxInstanceCtrl:GetInstanceChapterRewardList()
    ---@type LxInstanceWorldObj
    local worldObj
    ---@type table<number,LxInstanceRewardObj>
    local rewardObjs
    ---@type LxInstanceRewardObj
    local rewardObj
    ---@type LxInstanceMapObj
    local mapObj
    ---@type LxInstanceWorldObj[]
    local worldObjs = ModuleCenter.Instance:GetWorldObjs()
    local initInsWorldRefs = self:GetInitInsWorldRefList()
    ---@type V_InsmapRef[]
    local belongChapterInsmapRefs
    local worldRefId,mapRefId
    local isOpenMap,isPassMap,isRewardMap,isCanReward
    ---@type V_InsWorldRewardRef
    local iwrRef

    for i,worldRef in ipairs(initInsWorldRefs) do
        worldRefId = worldRef.refId
        worldObj = worldObjs[worldRefId]
        if worldObj then
            rewardObjs = worldObj.rewardObjs
            belongChapterInsmapRefs = self:GetInitInsmapRefsByBelongChapterId(worldRefId)
            if belongChapterInsmapRefs and #belongChapterInsmapRefs > 0 then
                local isAllReward = false
                if worldObj:CheckWorldIsPass() then
                    --- 已通关，检查奖励是否全部领取
                    local alreadyRecNum = 0
                    local rewardNum = #belongChapterInsmapRefs
                    for ii,mapRef in ipairs(belongChapterInsmapRefs) do
                        mapRefId = mapRef.refId
                        iwrRef = self:GetInitInsWorldRewardsByMapRefId(mapRefId)
                        if rewardObjs[iwrRef.refId] then
                            alreadyRecNum = alreadyRecNum + 1
                        end
                    end
                    isAllReward = alreadyRecNum >= rewardNum
                end
                if not isAllReward then
                    --- 未通关 / 已通过但有未领取的
                    local list = {}
                    for ii,mapRef in ipairs(belongChapterInsmapRefs) do
                        mapRefId = mapRef.refId
                        mapObj = worldObj:GetMapObj(mapRefId)
                        iwrRef = self:GetInitInsWorldRewardsByMapRefId(mapRefId)
                        isOpenMap = mapObj ~= nil
                        isPassMap,isCanReward = false,false
                        rewardObj = rewardObjs[iwrRef.refId]
                        isRewardMap = rewardObj ~= nil and rewardObj:IsAlreadyReceived()
                        if not isRewardMap and isOpenMap then
                            isCanReward = mapObj:IsPassMap()
                        end
                        if isOpenMap then
                            isPassMap = mapObj:IsPassMap()
                        end
                        table.insert(list,{
                            mapObj = mapObj,
                            mapRef = mapRef,
                            iwrRef = iwrRef,
                            isOpenMap = isOpenMap,
                            isPassMap = isPassMap,
                            rewardObj = rewardObj,
                            isRewardMap = isRewardMap,
                            isCanReward = isCanReward,
                        })
                    end
                    return list
                end
            end
        end
    end

    local endWorldRef = initInsWorldRefs[#initInsWorldRefs]
    worldRefId = endWorldRef.refId
    worldObj = worldObjs[worldRefId]
    if worldObj then
        rewardObjs = worldObj.rewardObjs
        belongChapterInsmapRefs = self:GetInitInsmapRefsByBelongChapterId(worldRefId)
        if belongChapterInsmapRefs and #belongChapterInsmapRefs > 0 then
            local isAllReward = false
            if worldObj:CheckWorldIsPass() then
                --- 已通关，检查奖励是否全部领取
                local alreadyRecNum = 0
                local rewardNum = #belongChapterInsmapRefs
                for ii,mapRef in ipairs(belongChapterInsmapRefs) do
                    mapRefId = mapRef.refId
                    iwrRef = self:GetInitInsWorldRewardsByMapRefId(mapRefId)
                    if rewardObjs[iwrRef.refId] then
                        alreadyRecNum = alreadyRecNum + 1
                    end
                end
                isAllReward = alreadyRecNum >= rewardNum
            end
            if not isAllReward then
                --- 未通关 / 已通过但有未领取的
                local list = {}
                for ii,mapRef in ipairs(belongChapterInsmapRefs) do
                    mapRefId = mapRef.refId
                    mapObj = worldObj:GetMapObj(mapRefId)
                    iwrRef = self:GetInitInsWorldRewardsByMapRefId(mapRefId)
                    isOpenMap = mapObj ~= nil
                    isPassMap,isCanReward = false,false
                    rewardObj = rewardObjs[iwrRef.refId]
                    isRewardMap = rewardObj ~= nil and rewardObj:IsAlreadyReceived()
                    if not isRewardMap and isOpenMap then
                        isCanReward = mapObj:IsPassMap()
                    end
                    if isOpenMap then
                        isPassMap = mapObj:IsPassMap()
                    end
                    table.insert(list,{
                        mapObj = mapObj,
                        mapRef = mapRef,
                        iwrRef = iwrRef,
                        isOpenMap = isOpenMap,
                        isPassMap = isPassMap,
                        rewardObj = rewardObj,
                        isRewardMap = isRewardMap,
                        isCanReward = isCanReward,
                    })
                end
                return list
            end
        end
    end
    return {}
end



function LxInstanceCtrl:GetInstanceNoFinishPointObjs()
    local resultList = {}
    local breakCell
    ---@type table<number,LxInstancePointObj> 格子下标转 pointObj
    local cell2TargetObjs
    ---@type LxInstancePointObj
    local pointObj = nil
    ---@type LxInstanceWorldObj[]
    local worldObjs = ModuleCenter.Instance:GetWorldObjs()
    for worldRefId,worldObj in pairs(worldObjs) do
        for mapRefId,mapObj in pairs(worldObj.mapObjs) do
            if #mapObj.targetObjs > 0 then
                breakCell = mapObj.breakCell
                if #breakCell > 0 then
                    cell2TargetObjs = mapObj.cell2TargetObjs
                    for i,v in ipairs(breakCell) do
                        pointObj = cell2TargetObjs[v]
                        if pointObj and not pointObj.finish then
                            table.insert(resultList,{
                                worldRefId = worldRefId,
                                mapRefId = mapRefId,
                                mapObj = mapObj,
                                pointObj = pointObj,
                            })
                        end
                    end
                end
            end
        end
    end
    return resultList
end


function LxInstanceCtrl:ParseInsPointTalkDatas(eventRefId)
    if not self._initInsPointTalkMap then
        self._initInsPointTalkMap = {}
    end
    local initInsPointTalkData = self._initInsPointTalkMap[eventRefId]
    if not initInsPointTalkData then
        local pointRef = LxDataHelper.GetInsPointRef(eventRefId)
        if pointRef then
            local talk = pointRef.talk
            if talk and #talk > 0 then
                initInsPointTalkData = {}
                for i,v in ipairs(talk) do
                    v = string.split(v,"=")
                    initInsPointTalkData[checknumber(v[1])] = checknumber(v[2])
                end
            end
        end
    end
    return initInsPointTalkData
end


---@param pointObj LxInstancePointObj
---@param gameParams table 必须包含有 mapObj:LxInstanceMapObj
function LxInstanceCtrl:DoStoryOpenEventUI(pointObj,gameParams)
    local talkDatas = self:ParseInsPointTalkDatas(pointObj.eventRefId)
    if not talkDatas then
        self:OpenEventUI(pointObj,gameParams)
        return
    end
    local storyFunc = gameParams.storyFunc
    if storyFunc then
        storyFunc()
        return
    end
    self:OpenStoryUI(talkDatas,InstanceStoryTypeEnum.PreTrigger,function()
        self:OpenEventUI(pointObj,gameParams)
    end)
end

