end


function LxInstanceCtrl:OpenStoryUI(talkDatas,stroyType,callback,endCb)
    local storyId = talkDatas[stroyType]
    if storyId and storyId > 0 then
        self:OpenInstanceStory({
            refId = storyId,
            callBack = callback,
            endCb = endCb,
        })
    else
        if callback then callback() end
        if endCb then endCb() end
    end
end

function LxInstanceCtrl:OpenInstanceStory(param)
    param.autoInsPlay = self:GetAutoPlayState()
    ShowPanel(UiNames.Story,param)
end

function LxInstanceCtrl:GetAutoPlayState()
    return false
end

---@param pointObj LxInstancePointObj
---@param gameParams table 必须包含有 mapObj:LxInstanceMapObj
function LxInstanceCtrl:OpenEventUI(pointObj,gameParams)
    if not pointObj then
        --- 首领来袭
        ShowPanel(UiNames.InstanceBoss,{
            gameParams = gameParams,
        })
        return
    end
    local eventType = pointObj.eventType
    if eventType == InstanceTypeEnum.Battle then
    elseif eventType == InstanceTypeEnum.Supperzzle then
        ShowPanel(UiNames.InstanceSupperzzle,{
            pointRefId = pointObj.eventRefId,
            pointObj = pointObj,
            gameParams = gameParams,
        })
    elseif eventType == InstanceTypeEnum.Flop then
        ShowPanel(UiNames.InstanceFlop,{
            pointRefId = pointObj.eventRefId,
            pointObj = pointObj,
            gameParams = gameParams,
        })
    elseif eventType == InstanceTypeEnum.Chess then
        ShowPanel(UiNames.InstanceChess,{
            pointRefId = pointObj.eventRefId,
            pointObj = pointObj,
            gameParams = gameParams,
        })
    elseif eventType == InstanceTypeEnum.Turntable then
        ShowPanel(UiNames.InstanceTurntable,{
            pointRefId = pointObj.eventRefId,
            pointObj = pointObj,
            gameParams = gameParams,
        })
    end
end




function LxInstanceCtrl:GetInitInsRewardsMap(eventReward)
    if not self._initInsRewardsMap then
        self._initInsRewardsMap = {}
    end
    local initInsRewards = self._initInsRewardsMap[eventReward]
    if not initInsRewards then
        initInsRewards = {}
        local type,typeLen
        for k,v in pairs(GameTable.InsRewardRef) do
            if v.rewardGroup == eventReward then
                type = string.split(v.type,"=")
                local typeInfo = {}
                typeLen = #type

                --- 1:事件完成固定奖励，3:随机奖励
                typeInfo.rewardType = checknumber(type[1])
                if typeLen > 1 then
                    if typeLen > 2 then
                        --- 4:评级奖励
                        typeInfo.min = checknumber(type[2])
                        typeInfo.max = checknumber(type[3])
                    else
                        --- 3:胜/平/负奖励
                        typeInfo.status = checknumber(type[2])
                    end
                end
                local rewardList = {}
                if typeInfo.rewardType == 3 then
                    rewardList = LxDataHelper.ParseItemList(string.split(v.reward,","))
                else
                    rewardList = LxDataHelper.ParseItemStrList(v.reward)
                end
                table.insert(initInsRewards,{
                    refId = k,
                    rewardGroup = eventReward,
                    type = v.type,
                    typeInfo = typeInfo,
                    rewardList = rewardList,
                })
            end
        end
        self._initInsRewardsMap[eventReward] = initInsRewards
    end
    return initInsRewards
end



function LxInstanceCtrl:GetOnHookQuickCostList()
    local instanceHookObj = ModuleCenter.Instance:GetInstanceHookObj()
    if not instanceHookObj then return {} end

    if instanceHookObj.hasQuickFreeCount then return {} end
    if not instanceHookObj.hasQuickCount then return {} end

    local curIdx = instanceHookObj.quickCount + 1
    local ref = GameTable.InsHookQuikRef[curIdx]
    if not ref then
        if not self._insHookQuikMaxId then
            local maxId
            for k,v in pairs(GameTable.InsHookQuikRef) do
                if not maxId then
                    maxId = k
                elseif maxId < k then
                    maxId = k
                end
            end
            self._insHookQuikMaxId = maxId
        end
        ref = GameTable.InsHookQuikRef[self._insHookQuikMaxId]
    end
    if not ref then return {} end

    local rateItemNum = self:GetVipLowerConsumeRate()

    ---@type V_Item[]
    local cost = LxDataHelper.ParseItemStrList(ref.cost) or {}
    local list = {}
    local num
    for i,v in ipairs(cost) do
        num = v.num * rateItemNum
        if num < 1 then num = 1 end
        table.insert(list,{
            type = v.type,
            refId = v.refId,
            num = num,
        })
    end
    return list
end

function LxInstanceCtrl:GetVipLowerConsumeRate()
    local rateItemNum = 1
    local vipLevel = ModuleCenter.Role:GetRoleVipLevel()
    if vipLevel then
        local vipModule = ModuleCenter.Vip
        local vipRef = vipModule:GetVipCfg(vipLevel)
        if vipRef and #vipRef.vipBuffList > 0 then
            local logStr = {}
            ---@type V_VipBuffRef
            local vipBuffRef
            ---@type V_SysBuffRef
            local sysBuffRef
            local sysBuffRefId,sysBuffId,sysBuffValue
            for i,vipBuffId in ipairs(vipRef.vipBuffList) do
                vipBuffRef = vipModule:GetVipBuffCfg(vipBuffId)
                sysBuffRefId = vipBuffRef and vipBuffRef.sysBuffRefId
                if sysBuffRefId and sysBuffRefId > 0 then
                    sysBuffRef = GameTable.SysBuffRef[sysBuffRefId]
                    if sysBuffRef then
                        sysBuffId = sysBuffRef.sysBuffId or 0
                        if sysBuffId == 107 then
                            sysBuffValue = checknumber(sysBuffRef.sysBuffValue) or 0
                            if sysBuffValue > 0 then
                                table.insert(logStr,"sysbuffid:"..sysBuffId..",sysBuffValue:"..sysBuffValue)
                                rateItemNum = rateItemNum - sysBuffValue / 100
                            end
                        end
                    end
                end
            end
            if LOG_ERROR_ENABLED then
                printError("打印加成：",">> " .. table.concat(logStr,","))
            end
        end
    end
    return rateItemNum
end

function LxInstanceCtrl:GetInsHookShowRefList()
    local instanceHookObj = ModuleCenter.Instance:GetInstanceHookObj()
    local activeShowMap = instanceHookObj and instanceHookObj.activeShowMap or {}
    local level = instanceHookObj and instanceHookObj.level or 0
    local isUpLevel = level > 0
    local list = {}
    local ref = GameTable.InsHookShowRef
    local isAct,isCanAct
    local getLv,firstLv
    for k,v in pairs(ref) do
        getLv = v.getLv
        firstLv = getLv
        isAct = activeShowMap[k] and true or false
        isCanAct = false
        if not isAct and isUpLevel then
            isCanAct = level >= firstLv
        end
        table.insert(list,{
            refId = k,
            sort = v.sort,
            name = I18nText(v.name),
            rewardType = v.rewardType,
            reward = v.reward,
            getLv = getLv,
            firstLv = firstLv,
            isAct = isAct,
            isCanAct = isCanAct,
        })
    end
    table.sort(list,function(a, b) return a.sort < b.sort end)
    return list
end

