---@param ref V_InsHookLvRef
---@return V_Item[]
function LxInstanceCtrl:_GetEarningsRewardList(ref)
    if not ref then return {} end

    local allMin = 24 * 60
    local list = {}
    local hookReward = ref.hookReward
    if hookReward and #hookReward > 0 then
        local dataList = LxDataHelper.ParseItemList(hookReward)
        for i,v in ipairs(dataList) do
            v.num = v.num * allMin
            table.insert(list,v)
        end
    end
    local hookRewardShow = ref.hookRewardShow
    if hookRewardShow and #hookRewardShow > 0 then
        local dataList = LxDataHelper.ParseItemList(hookRewardShow)
        for i,v in ipairs(dataList) do
            v.num = v.num * allMin
            table.insert(list,v)
        end
    end
    return list
end

