function LxInstanceCtrl:GetInstanceRed()
    if self:CheckInstanceRedPoint() then return 1 end
    return 0
end

function LxInstanceCtrl:CheckInstanceRedPoint()
    if self:CheckOnHookRedPoint() then return true end
    if self:CheckIsUnlockReward() then return true end
    if self:CheckChapterRewardIsGet() then return true end
    if CtrlCenter.MemoryStore:CheckMemoryRedPoint() then return true end
end

function LxInstanceCtrl:CheckOnHookRedPoint()
    if self:CheckOnHookQuickRedPoint() then return true end
    if self:CheckIsNoticeTime() then return true end
end

---@return boolean 快速挂机红点
function LxInstanceCtrl:CheckOnHookQuickRedPoint()
    if self:CheckIsQuickFreeCount() then return true end
    if self:CheckOnHookIsCanUpLevel() then return true end
end

---@return boolean 是否有免费挂机
function LxInstanceCtrl:CheckIsQuickFreeCount()
    local hookObj = ModuleCenter.Instance:GetInstanceHookObj()
    return hookObj and hookObj.hasQuickFreeCount
end

---@return boolean 挂机升级是否可以升级
function LxInstanceCtrl:CheckOnHookIsCanUpLevel()
    if self:CheckOnHookIsFullLv() then return false end

    local upCost = self:GetCurOnHookUpLevelCostList()
    if not upCost or #upCost < 0 then return false end

    return CtrlCenter.Item:CheckItemListEnough(upCost)
end

---@return boolean 挂机是否满级
function LxInstanceCtrl:CheckOnHookIsFullLv()
    local instanceHookObj = ModuleCenter.Instance:GetInstanceHookObj()
    if not instanceHookObj then return true end
    local nextLevel = instanceHookObj.level + 1
    local nextRef = GameTable.InsHookLvRef[nextLevel]
    return nextRef == nil
end

---@return boolean 是否已经到达提示时间
function LxInstanceCtrl:CheckIsNoticeTime()
    local instanceHookObj = ModuleCenter.Instance:GetInstanceHookObj()
    if not instanceHookObj then return false end
    local onHookNoticeTime = GameTable.InsConfigRef["onHookNoticeTime"]
    local lastTime = LxUtil.OSTime() - instanceHookObj.startTime
    if lastTime >= onHookNoticeTime then return true end
end

---@return boolean 挂机奖励是否可升级 挂机显示
function LxInstanceCtrl:CheckIsUnlockReward()
    local list = self:GetInsHookShowRefList()
    for i,v in ipairs(list) do
        if v.isCanAct then return true end
    end
    return false
end

---@return boolean 章节奖励是否可领取
function LxInstanceCtrl:CheckChapterRewardIsGet()
    local instanceModule = ModuleCenter.Instance
    ---@type LxInstanceWorldObj
    local worldObj
    ---@type table<number,LxInstanceRewardObj> 奖励列表
    local rewardObjs
    ---@type LxInstanceRewardObj
    local rewardObj
    ---@type table<number,LxInstanceMapObj> 地图数据
    local mapObjs
    ---@type LxInstanceMapObj
    local mapObj
    ---@type V_InsmapRef[]
    local sortInsmapRefs
    local worldRefId
    ---@type V_InsWorldRewardRef
    local iwrRef
    ---@type V_InsWorldRef[]
    local initInsWorldRefs = self:GetInitInsWorldRefList()
    for i,v in ipairs(initInsWorldRefs) do
        worldRefId = v.refId
        worldObj = instanceModule:GetWorldObj(worldRefId)
        if worldObj then
            mapObjs = worldObj.mapObjs
            rewardObjs = worldObj.rewardObjs
            sortInsmapRefs = self:GetInitInsmapRefsByBelongChapterId(worldRefId)
            for ii,vv in ipairs(sortInsmapRefs) do
                mapObj = mapObjs[vv.refId]
                if mapObj and mapObj:IsPassMap() then
                    iwrRef = self:GetInitInsWorldRewardsByMapRefId(mapObj.refId)
                    if iwrRef then
                        rewardObj = rewardObjs[iwrRef.refId]
                        if rewardObj and rewardObj:IsCanReceived() then
                            return true
                        elseif not rewardObj then
                            return true
                        end
                    end
                end
            end
        end
    end
end

function LxInstanceCtrl:CheckTreeRP()
    if self:CheckIsQuickFreeCount() then return true end
    if self:CheckIsNoticeTime() then return true end
    if self:CheckOnHookIsCanUpLevel() then return true end
end

function LxInstanceCtrl:RefreshMainCityRP()
    FireEvent(EventNames.REFRESH_MAINCITYBOT_RP,{botFuncType = 3})
end

function LxInstanceCtrl:CheckInstanceQuestRP()
    local questList
    local questTypeList = CtrlCenter.Quest:GetMainQuestBelongList()
    for i,v in ipairs(questTypeList) do
        questList = v.questList
        for idx,val in ipairs(questList) do
            if CtrlCenter.Quest:CheckQuestIsCanGet(val.questId) then
                return true
            end
        end
    end
    return false
end

function LxInstanceCtrl:OnAutoPlayFinish()

end

---@return boolean 跳过战斗
function LxInstanceCtrl:GetInsJumpFormationState()
    return checkbool(LxPlayerPrefs.InsSkipFormation)
end

function LxInstanceCtrl:SetInsJumpFormationState(bJump)
    LxPlayerPrefs.InsSkipFormation = bJump and "true" or "false"
end

return LxInstanceCtrl